"use strict";(self.webpackChunkwoocommerce_ebay_connector=self.webpackChunkwoocommerce_ebay_connector||[]).push([[215],{268(e,r,a){a.r(r),a.d(r,{comp:()=>d,data:()=>m});var t=a(641);const o=a.p+"assets/img/import-order-from-ebay.f05c2fea.webp",n=a.p+"assets/img/order-source.616b50fc.webp",s=a.p+"assets/img/auto-order-import-setting.d4c703f9.webp",i=a.p+"assets/img/order-import-default-status.8a144fd2.webp",c={},d=(0,a(6262).A)(c,[["render",function(e,r){return(0,t.uX)(),(0,t.CE)("div",null,[...r[0]||(r[0]=[(0,t.Fv)('<h1 id="order-management-–-woocommerce-ebay-connector" tabindex="-1"><a class="header-anchor" href="#order-management-–-woocommerce-ebay-connector"><span>Order Management – WooCommerce eBay Connector</span></a></h1><p>This section allows the admin to import and manage eBay marketplace orders directly within the WooCommerce store, ensuring a centralized order processing workflow.</p><hr><h2 id="importing-orders-from-ebay" tabindex="-1"><a class="header-anchor" href="#importing-orders-from-ebay"><span>Importing Orders from eBay</span></a></h2><p>The admin can manually fetch orders from the eBay store to the WooCommerce store using specific date ranges.</p><ul><li>To manage orders, navigate to <strong>WC eBay Connector → Manage Orders</strong>.</li><li>This section provides a dedicated tab for initiating order imports.</li></ul><p><a class="doc-image-link" href="./assets/import-order-from-ebay.webp"><img src="'+o+'" alt="Import Orders"></a></p><h3 id="how-to-import-ebay-orders" tabindex="-1"><a class="header-anchor" href="#how-to-import-ebay-orders"><span>How to Import eBay Orders</span></a></h3><ul><li>Click on the <strong>Import Orders from eBay</strong> button.</li><li>The admin must define the <strong>Start Time From</strong> and <strong>Start Time To</strong> to specify the order creation period.</li><li>Click the <strong>Start</strong> button to begin the data retrieval process.</li><li>Once processed, the orders will be listed within the WooCommerce store for further management.</li></ul><hr><h2 id="tracking-order-sources" tabindex="-1"><a class="header-anchor" href="#tracking-order-sources"><span>Tracking Order Sources</span></a></h2><p>To simplify management, the WooCommerce Orders list includes an <strong>Order Source</strong> column.</p><p><a class="doc-image-link" href="./assets/order-source.webp"><img src="'+n+'" alt="Order Source"></a></p><ul><li>This allows the admin to quickly identify whether an order originated from the WooCommerce store or the eBay marketplace.</li><li>This feature helps in efficient order tracking and inventory reconciliation.</li></ul><hr><h2 id="automatic-ebay-order-synchronization" tabindex="-1"><a class="header-anchor" href="#automatic-ebay-order-synchronization"><span>Automatic eBay Order Synchronization</span></a></h2><p>The admin can configure the module to automatically fetch orders from eBay at regular intervals.</p><ul><li>To enable this, navigate to <strong>WC eBay Connector → eBay Settings → General Settings</strong>.</li><li>Toggle the <strong>Auto Order Import</strong> option to enabled.</li><li>The system executes an automatic check every <strong>10 minutes</strong> and retrieves all orders placed within the last <strong>15 minutes</strong>.</li></ul><p><a class="doc-image-link" href="./assets/auto-order-import-setting.webp"><img src="'+s+'" alt="Auto Order Import"></a></p><blockquote><p>[!IMPORTANT] To ensure correct order mapping, all associated products must be pre-imported or synchronized before real-time order import can function.</p></blockquote><hr><h2 id="configuring-default-order-status" tabindex="-1"><a class="header-anchor" href="#configuring-default-order-status"><span>Configuring Default Order Status</span></a></h2><p>The admin can define a specific status for orders arriving from the eBay marketplace.</p><ul><li>Navigate to <strong>WC eBay Connector → eBay Settings → General Settings</strong>.</li><li>Locate the <strong>eBay Imported Order Status</strong> field.</li><li>Select the preferred status (e.g., Processing, On Hold, Completed) that should be applied to all imported eBay orders.</li></ul><p><a class="doc-image-link" href="./assets/order-import-default-status.webp"><img src="'+i+'" alt="Order Status"></a></p>',25)])])}]]),m=JSON.parse('{"path":"/documentation/order-management.html","title":"Order Management – WooCommerce eBay Connector","lang":"en-US","frontmatter":{"prev":"/documentation/export-product.html","next":false},"git":{"contributors":[{"name":"shakir.hussain","username":"","email":"shakir.hussain421@webkul.in","commits":1},{"name":"aadesh","username":"","email":"aadesh.8209@webkul.in","commits":1}],"changelog":[{"hash":"2d5c39163a248635a79c60d8508c0716b0a11c03","time":1772114569000,"email":"aadesh.8209@webkul.in","author":"aadesh","message":"add export product"},{"hash":"277c5a1bdc13e06551e102ee26c728b6b048e50b","time":1771481506000,"email":"shakir.hussain421@webkul.in","author":"shakir.hussain","message":"updated ebay blog and move to dev"}]},"filePathRelative":"documentation/order-management.md"}')}}]);